sqlMap.insert:

INSERT INTO tbl_pms_item_attachment (
	tenant_id, 		item_id, 			file_path, 		file_size, 		file_name
)
VALUES (
	#tenantId#, 	#last_insert_id#, 	#filePath#, 	#fileSize#, 	#fileName#
)


INSERT INTO TBL_PMS_MAINLIST (
	TENANT_ID,	USER_ID,	PROJECT_ID,		KANBAN_ORDER
)
VALUES (
	#tenantId#,	#userId#,	#projectId#,	#orderStatus#
)

select.isEqual:
SELECT 0 AS memberId, A.CN AS userId, A.DISPLAYNAME AS userName, A.DISPLAYNAME2 AS userName2, B.DISPLAYNAME AS userDeptname, B.DISPLAYNAME2 AS userDeptname2, A.tenant_id AS tenantId, $groupId$ AS groupId, $memberRoleId$ AS memberRoleId FROM tbl_usermaster A LEFT JOIN tbl_deptmaster B ON A.department = B.CN AND A.tenant_id = B.tenant_id WHERE A.tenant_id = #tenantId# AND A.CN IN (
#userId[]#
)

select.isNotEqual:
SELECT 0 AS memberId, CN AS userId, DISPLAYNAME AS userName, DISPLAYNAME2 AS userName2, DISPLAYNAME AS userDeptname, DISPLAYNAME2 AS userDeptname2, tenant_id as tenantId, $groupId$ as groupId, $memberRoleId$ as memberRoleId FROM tbl_deptmaster WHERE tenant_id = #tenantId# AND CN IN (
#userId[]#
)
